// Kendte udvalg fra Middelfart Kommune
// Disse IDer bruges til at finde nye møder
const committees = [
  {
    name: 'Økonomiudvalget',
    meetings: [
      { id: 'b0e726fa-1955-4e52-a751-0438b68f27bd', date: '2026-03-23' },
      { id: '2923c671-65f8-4678-87c4-729882b2baa4', date: '2026-02-22' }
    ]
  },
  {
    name: 'Teknisk Udvalg',
    meetings: [
      { id: '51cb8f11-a4c1-4e70-ab50-9fc67e3bd83f', date: '2026-03-09' },
      { id: 'a331bbc5-5d80-4981-8fe5-3f5bf527a520', date: '2026-02-16' }
    ]
  },
  {
    name: 'Beskæftigelses- og Arbejdsmarkedsudvalget',
    meetings: [
      { id: 'e7f06447-4f8b-47cd-9566-d6255a2ab419', date: '2026-04-09' },
      { id: '0cd691ad-4a66-49aa-8dcd-c4defd0c2dd7', date: '2026-03-04' }
    ]
  },
  {
    name: 'Børn-, Kultur- og Fritidsudvalget',
    meetings: []
  },
  {
    name: 'Klima-, Natur- og Genbrugsudvalget',
    meetings: []
  },
  {
    name: 'Distriktsudvalget',
    meetings: []
  }
];

// Lav én item pr. møde
const items = [];
for (const c of committees) {
  for (const m of c.meetings) {
    items.push({
      json: {
        udvalg: c.name,
        møde_id: m.id,
        møde_dato: m.date,
        api_url: `https://dagsordener.middelfart.dk/api/agenda/dagsorden/${m.id}`,
        kilde_url: `https://dagsordener.middelfart.dk/vis?id=${m.id}`
      }
    });
  }
}

return items;

// Udtræk dagsordenspunkter fra API-response
// FirstAgenda API returnerer typisk en struktur med Items/AgendaItems
const input = $input.first().json;
const meta = {
  udvalg: $('Kendte Udvalg & Møder').first().json.udvalg,
  møde_id: $('Kendte Udvalg & Møder').first().json.møde_id,
  møde_dato: $('Kendte Udvalg & Møder').first().json.møde_dato,
  kilde_url: $('Kendte Udvalg & Møder').first().json.kilde_url
};

// Forsøg at parse dagsordenspunkter fra forskellige mulige strukturer
let items = [];

if (input.Items && Array.isArray(input.Items)) {
  items = input.Items;
} else if (input.AgendaItems && Array.isArray(input.AgendaItems)) {
  items = input.AgendaItems;
} else if (Array.isArray(input)) {
  items = input;
} else {
  // Hvis strukturen er ukendt, send hele responsen som ét punkt
  items = [{ Title: 'Fuld dagsorden', Content: JSON.stringify(input).substring(0, 5000) }];
}

const result = [];
for (let i = 0; i < items.length; i++) {
  const item = items[i];
  const title = item.Title || item.title || item.Name || item.name || `Punkt ${i + 1}`;
  const content = item.Content || item.content || item.Description || item.description || item.Text || item.text || '';
  // Strip HTML tags for cleaner text
  const cleanContent = typeof content === 'string' ? content.replace(/<[^>]*>/g, ' ').replace(/\s+/g, ' ').trim() : JSON.stringify(content);

  result.push({
    json: {
      ...meta,
      punkt_nr: item.Number || item.number || (i + 1),
      titel: title,
      indhold: cleanContent.substring(0, 4000), // Begræns til 4000 tegn for AI
      fuld_indhold: cleanContent
    }
  });
}

return result.length > 0 ? result : [{ json: { ...meta, punkt_nr: 0, titel: 'Ingen punkter fundet', indhold: '', fuld_indhold: '' } }];

