// Parse Claude's response og kombiner med mødedata
const aiResponse = $input.first().json;
const punkt = $('Udtræk Punkter').first().json;

let classification = {};
try {
  // Claude API returnerer content[0].text
  const text = aiResponse.content?.[0]?.text || aiResponse.text || JSON.stringify(aiResponse);
  // Find JSON i svaret
  const jsonMatch = text.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    classification = JSON.parse(jsonMatch[0]);
  }
} catch (e) {
  classification = {
    kategori: 'andet',
    relevans_score: 1,
    resumé: 'Kunne ikke klassificeres automatisk',
    relevans_begrundelse: 'AI-fejl: ' + e.message,
    foreslaaet_handling: 'overvåg'
  };
}

const now = new Date().toISOString();

return [{
  json: {
    id: `${punkt.møde_id}-${punkt.punkt_nr}`,
    møde_id: punkt.møde_id,
    udvalg: punkt.udvalg,
    møde_dato: punkt.møde_dato,
    punkt_nr: punkt.punkt_nr,
    titel: punkt.titel,
    kategori: classification.kategori || 'andet',
    relevans_score: classification.relevans_score || 1,
    resumé: classification.resumé || '',
    relevans_begrundelse: classification.relevans_begrundelse || '',
    foreslaaet_handling: classification.foreslaaet_handling || 'overvåg',
    status: classification.foreslaaet_handling || 'overvåg',
    vores_input: '',
    vores_vinkel: '',
    tjekket_ind_af: '',
    tjekket_ind_dato: '',
    kilde_url: punkt.kilde_url,
    oprettet: now
  }
}];

// Opsummering af hvad der blev hentet
const items = $input.all();
const summary = {
  total_punkter: items.length,
  tidspunkt: new Date().toISOString(),
  besked: `${items.length} dagsordenspunkter hentet og klassificeret.`
};
return [{ json: summary }];
